#include<bits/stdc++.h>
using namespace std;
stack<string> s[10000];string x,cmd;int n,t;
int main(){
	cin>>t;
	for(int i=0;i<t;i++){
		cin>>n;
		for(int J=0;J<n;J++){
			cin>>cmd;
			if(cmd=="push")cin>>x,s[i].push(x);
			else if(cmd=="pop"){
				if(s[i].empty()){cout<<"Empty"<<endl;}
        		else{s[i].pop();}
			}
			else if(cmd=="query"){
				if(s[i].empty()){cout<<"Anguei!"<<endl;}
     		    else{cout<<s[i].top()<<endl;}
			}
			else if(cmd=="size")cout<<s[i].size()<<endl;
		}
	}
	return false;
}
